#include<bits/stdc++.h>
using namespace std;
stack<pair<int,int>> s;
int main()
{
    int n;
    scanf("%d",&n);
    long long ans=0;
    for(int i=1;i<=n;i++)
    {
        int x;
        scanf("%d",&x);
        pair<int,int> v={x,1};
        while(!s.empty()&&s.top().first<=x)
        {
            ans+=s.top().second;
            if(s.top().first==x)
            {
                v.second+=s.top().second;
            }
            s.pop();
        }
        if(!s.empty())
        {
            ans++;
        }
        s.push(v);
    }
    printf("%lld",ans);
    return 0;
}
